import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import apiClient from "../../../shared/api/client";

const TEMPLATES = [
  { id: 1, label: "Пустая форма", icon: "📑", bg: "#fff" },
  { id: 2, label: "Контактная информация", bg: "#d1fae5", questions: [
    { title: "Ваше имя", type: "text", options: [], required: true },
    { title: "Ваша электронная почта", type: "text", options: [], required: true },
    { title: "Ваш номер телефона", type: "text", options: [], required: true },
    { title: "Название компании", type: "text", options: [], required: false },
    { title: "Город проживания", type: "text", options: [], required: false },
    { title: "По какому вопросу вы нас контактируете?", type: "dropdown", options: ["Продажи", "Поддержка", "Партнёрство", "Другое"], required: true }
  ]},
  { id: 3, label: "Ответ на приглашение", bg: "#fef9c3", questions: [
    { title: "Ваше имя", type: "text", options: [], required: true },
    { title: "Сколько гостей вы приведёте?", type: "dropdown", options: ["1", "2", "3", "4", "5+"], required: true },
    { title: "Вы посетите мероприятие?", type: "radio", options: ["Да, обязательно", "Возможно", "Нет, спасибо"], required: true },
    { title: "У вас есть диетические ограничения?", type: "checkbox", options: ["Вегетарианское", "Веганское", "Без глютена", "Нет"], required: false },
    { title: "Какие блюда вам нравятся больше всего?", type: "textarea", options: [], required: false },
    { title: "Оценка вашего интереса", type: "scale", options: [], required: true }
  ]},
  { id: 4, label: "Приглашение на вече...", bg: "#fce7f3", questions: [
    { title: "Ваше имя", type: "text", options: [], required: true },
    { title: "Вы приходили на наши мероприятия раньше?", type: "radio", options: ["Да", "Нет", "В первый раз"], required: true },
    { title: "Что вас интересует больше всего?", type: "checkbox", options: ["Сетевое взаимодействие", "Образовательные семинары", "Развлечения", "Еда и напитки"], required: true },
    { title: "Рекомендуете ли вы наши мероприятия друзьям?", type: "radio", options: ["Да, точно", "Возможно", "Нет"], required: true },
    { title: "Ваши замечания и предложения", type: "textarea", options: [], required: false },
    { title: "Оцените последнее мероприятие", type: "scale", options: [], required: true }
  ]},
  { id: 5, label: "Заказ футболки", bg: "#ede9fe", questions: [
    { title: "Ваше имя", type: "text", options: [], required: true },
    { title: "Выберите размер", type: "radio", options: ["XS", "S", "M", "L", "XL", "XXL"], required: true },
    { title: "Выберите точный цвет футболки", type: "dropdown", options: ["Чёрный", "Белый", "Синий", "Красный", "Зелёный"], required: true },
    { title: "Добавить карман с логотипом?", type: "radio", options: ["Да", "Нет"], required: true },
    { title: "Специальные пожелания по печати", type: "textarea", options: [], required: false },
    { title: "Как срочен ваш заказ?", type: "dropdown", options: ["Обычная доставка (7-10 дней)", "Ускоренная (3-5 дней)", "Срочная (1-2 дня)"], required: true }
  ]},
  { id: 6, label: "Регистрация на мероп...", bg: "#fef3c7", questions: [
    { title: "Полное имя", type: "text", options: [], required: true },
    { title: "Email адрес", type: "text", options: [], required: true },
    { title: "Компания", type: "text", options: [], required: false },
    { title: "Выберите дату посещения", type: "dropdown", options: ["15 апреля", "16 апреля", "17 апреля"], required: true },
    { title: "Какие тренинги вас интересуют?", type: "checkbox", options: ["Маркетинг", "Продажи", "Программирование", "Дизайн"], required: true },
    { title: "Как вы узнали о мероприятии?", type: "dropdown", options: ["Через друга", "Социальные сети", "Email рассылка", "Поиск в интернете"], required: true }
  ]}
];

export default function Home() {
  const navigate = useNavigate();
  const [surveys, setSurveys] = useState([]);
  const [view, setView] = useState("list");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [searchQuery, setSearchQuery] = useState("");
  const [creatingForm, setCreatingForm] = useState(false);

  useEffect(() => {
    loadSurveys();
  }, []);

  const createNewForm = async (template = null) => {
    setCreatingForm(true);
    if (template) {
      localStorage.setItem("templateQuestions", JSON.stringify(template.questions));
      localStorage.setItem("templateTitle", template.label.replace("...", ""));
    }
    setTimeout(() => {
      navigate("/editor");
      setCreatingForm(false);
    }, 300);
  };

  const logout = () => {
    setLoading(true);
    setTimeout(() => {
      localStorage.removeItem("token");
      localStorage.removeItem("user");
      navigate("/login");
    }, 200);
  };

  const loadSurveys = async () => {
    try {
      setError("");
      setLoading(true);
      const data = await apiClient.surveys.getAll();
      setSurveys(data.data || []);
    } catch (error) {
      console.error("Error loading surveys:", error);
      setError(`Ошибка при загрузке опросов: ${error.message}`);
    } finally {
      setLoading(false);
    }
  };

  const user = JSON.parse(localStorage.getItem("user") || "{}");

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=DM+Sans:wght@300;400;500;600&family=DM+Serif+Display&display=swap');
        
        @keyframes fadeIn {
          from {
            opacity: 0;
            transform: translateY(10px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }

        @keyframes slideDown {
          from {
            opacity: 0;
            max-height: 0;
          }
          to {
            opacity: 1;
            max-height: 400px;
          }
        }

        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
        body { font-family: 'DM Sans', sans-serif; background: #fff; animation: fadeIn 0.4s ease-out; }

        .navbar {
          display: flex;
          align-items: center;
          gap: 16px;
          padding: 12px 24px;
          height: auto;
          background: #fff;
          border-bottom: 1px solid #e5e7eb;
          position: sticky; top: 0; z-index: 100;
        }

        .nav-logo {
          display: flex; align-items: center; gap: 8px;
          text-decoration: none;
        }

        .nav-logo-icon {
          width: 32px; height: 32px;
          background: linear-gradient(135deg, #d1fae5, #6ee7b7);
          border-radius: 8px;
          display: flex; align-items: center; justify-content: center;
          font-size: 16px;
        }

        .nav-logo-text {
          font-family: 'DM Serif Display', serif;
          font-size: 18px; color: #4ade80;
        }

        .nav-spacer { flex: 1; }

        .nav-actions {
          display: flex; align-items: center; gap: 12px;
        }

        .nav-btn {
          background: none; border: none;
          font-size: 14px; color: #6b7280;
          cursor: pointer; font-family: 'DM Sans', sans-serif;
          transition: color 0.2s;
        }

        .nav-btn:hover { color: #4f46e5; }

        .logout-btn {
          background: #ef4444; color: #fff;
          border: none; padding: 8px 16px;
          border-radius: 6px; cursor: pointer;
          font-size: 14px; font-family: 'DM Sans', sans-serif;
        }

        .logout-btn:hover { background: #dc2626; }

        .nav-user {
          font-size: 14px; color: #6b7280;
        }

        .container {
          max-width: 1200px; margin: 0 auto;
          padding: 32px 24px;
        }

        .template-card {
          aspect-ratio: 1;
          border-radius: 12px;
          display: flex; flex-direction: column; 
          align-items: center; justify-content: center;
          cursor: pointer;
          transition: transform 0.2s, box-shadow 0.2s, background 0.2s;
          border: 2px solid #e5e7eb;
          font-size: 13px; text-align: center; padding: 16px;
          color: #374151; font-weight: 500;
        }

        .template-card:hover {
          transform: translateY(-8px);
          box-shadow: 0 8px 24px rgba(0,0,0,0.12);
          border-color: #4f46e5;
          background: #fafafa;
        }

        .template-icon {
          font-size: 32px; margin-bottom: 8px;
        }

        .survey-card {
          background: #fff; border-radius: 12px;
          border: 1px solid #e5e7eb;
          padding: 24px;
          cursor: pointer;
          transition: all 0.2s;
        }

        .survey-card:hover {
          transform: translateY(-4px);
          box-shadow: 0 8px 24px rgba(0,0,0,0.1);
          border-color: #4f46e5;
        }

        .survey-title {
          font-size: 18px; font-weight: 600;
          color: #111; margin-bottom: 12px;
          white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
        }

        .survey-meta {
          font-size: 13px; color: #9ca3af;
          margin-bottom: 16px;
        }

        .survey-actions {
          display: flex; gap: 8px;
        }

        .survey-action-btn {
          flex: 1; background: #f3f4f6; border: none;
          padding: 10px 12px; border-radius: 6px; cursor: pointer;
          font-size: 13px; color: #374151; font-weight: 500;
          transition: background 0.2s;
          font-family: 'DM Sans', sans-serif;
        }

        .survey-action-btn:hover { background: #e5e7eb; color: #111; }

        .toolbar-btn {
          background: #4f46e5; color: #fff;
          border: none; padding: 10px 24px;
          border-radius: 6px; cursor: pointer;
          font-size: 14px; font-family: 'DM Sans', sans-serif;
          font-weight: 600;
          transition: background 0.2s;
        }

        .toolbar-btn:hover { background: #4338ca; }

        .search-box {
          display: flex; align-items: center; gap: 10px;
          width: 100%; max-width: 700px;
          background: #fff; padding: 12px 20px;
          border-radius: 8px; border: 1px solid #d1d5db;
          box-shadow: 0 2px 8px rgba(0,0,0,0.08);
          position: relative;
          animation: fadeIn 0.3s ease-out;
        }

        .search-box:focus-within {
          border-color: #4f46e5;
          box-shadow: 0 4px 16px rgba(79,70,229,0.15);
        }

        .search-box input {
          flex: 1; background: none;
          border: none; outline: none;
          font-size: 15px; color: #1f2937;
          font-family: 'DM Sans', sans-serif;
        }

        .search-box input::placeholder { color: #9ca3af; }

        .search-icon { color: #9ca3af; font-size: 18px; }

        .search-results {
          position: absolute;
          top: 100%; left: 0; right: 0;
          background: #fff;
          border: 1px solid #e5e7eb;
          border-top: none;
          border-radius: 0 0 8px 8px;
          max-height: 320px;
          overflow-y: auto;
          z-index: 101;
          animation: slideDown 0.2s ease-out;
        }

        .search-result-item {
          padding: 12px 20px;
          border-bottom: 1px solid #f3f4f6;
          cursor: pointer;
          transition: background 0.2s;
        }

        .search-result-item:last-child { border-bottom: none; }

        .search-result-item:hover { background: #f9fafb; }

        .search-result-title {
          font-size: 14px; font-weight: 500; color: #1f2937;
          margin-bottom: 2px;
        }

        .search-result-meta {
          font-size: 12px; color: #9ca3af;
        }

        .header-wrapper {
          display: none;
        }
        }

        .header-content {
          max-width: 1200px; margin: 0 auto;
        }

        .templates-section {
          margin-bottom: 48px;
        }

        .templates-title {
          font-size: 18px; font-weight: 600;
          color: #111; margin-bottom: 20px;
        }

        .templates-grid {
          display: grid; grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
          gap: 16px;
        }

        .template-card {
          aspect-ratio: 1;
          border-radius: 12px;
          display: flex; flex-direction: column; 
          align-items: center; justify-content: center;
          cursor: pointer;
          transition: transform 0.2s, box-shadow 0.2s, background 0.2s;
          border: 2px solid #e5e7eb;
          font-size: 13px; text-align: center; padding: 16px;
          color: #374151; font-weight: 500;
        }

        .template-card:hover {
          transform: translateY(-8px);
          box-shadow: 0 8px 24px rgba(0,0,0,0.12);
          border-color: #4f46e5;
          background: #fafafa;
        }

        .template-icon {
          font-size: 40px; margin-bottom: 12px;
        }

        .surveys-title {
          font-size: 20px; font-weight: 600;
          color: #111; margin-bottom: 20px;
        }

        .surveys-grid {
          display: grid; grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
          gap: 16px;
        }

        .survey-card {
          background: #fff; border-radius: 12px;
          border: 1px solid #e5e7eb;
          padding: 24px;
          cursor: pointer;
          transition: all 0.2s;
        }

        .survey-card:hover {
          transform: translateY(-4px);
          box-shadow: 0 8px 24px rgba(0,0,0,0.1);
          border-color: #4f46e5;
        }

        .survey-title {
          font-size: 18px; font-weight: 600;
          color: #111; margin-bottom: 12px;
          white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
        }

        .survey-meta {
          font-size: 13px; color: #9ca3af;
          margin-bottom: 16px;
        }

        .survey-actions {
          display: flex; gap: 8px;
        }

        .survey-action-btn {
          flex: 1; background: #f3f4f6; border: none;
          padding: 10px 12px; border-radius: 6px; cursor: pointer;
          font-size: 13px; color: #374151; font-weight: 500;
          transition: background 0.2s;
          font-family: 'DM Sans', sans-serif;
        }

        .survey-action-btn:hover { background: #e5e7eb; color: #111; }
      `}</style>

      <nav className="navbar">
        <a className="nav-logo">
          <img src="/fromo.png" alt="Formo" style={{ width: "80px", height: "80px", marginRight: "auto" }} />
        </a>

        <div className="nav-actions">
          <span className="nav-user">{user.firstName}</span>
          <button className="nav-btn" onClick={loadSurveys} title="Обновить">●●●</button>
          <button className="logout-btn" onClick={logout}>Выход</button>
        </div>
      </nav>

      <div className="container" style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", minHeight: "calc(100vh - 120px)", paddingTop: "40px" }}>
        <div className="search-box" style={{ marginBottom: "60px", position: "relative" }}>
          <span className="search-icon">🔍</span>
          <input
            type="text"
            placeholder="Поиск форм..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            autoFocus
          />
          {searchQuery && surveys.filter(s => s.title.toLowerCase().includes(searchQuery.toLowerCase())).length > 0 && (
            <div className="search-results">
              {surveys.filter(s => s.title.toLowerCase().includes(searchQuery.toLowerCase())).map(survey => (
                <div 
                  key={survey._id}
                  className="search-result-item"
                  onClick={() => {
                    setSearchQuery("");
                    navigate(`/editor/${survey._id}`);
                  }}
                >
                  <div className="search-result-title">{survey.title}</div>
                  <div className="search-result-meta">{survey.questions?.length || 0} вопросов</div>
                </div>
              ))}
            </div>
          )}
        </div>

        {!searchQuery && (
          <div style={{ width: "100%", maxWidth: "1200px", animation: "fadeIn 0.4s ease-out" }}>

        {error && (
          <div style={{
            background: "#fee2e2",
            color: "#dc2626",
            padding: "12px 16px",
            borderRadius: "6px",
            marginBottom: "20px",
            fontSize: "14px",
            border: "1px solid #fecaca"
          }}>
            {error}
          </div>
        )}

        <div className="templates-section">
              <div className="templates-title">Начните с шаблона</div>
              <div className="templates-grid">
                {TEMPLATES.map(template => (
                  <div 
                    key={template.id}
                    className="template-card"
                    style={{ background: template.bg }}
                    onClick={() => createNewForm(template)}
                  >
                    <div className="template-icon">{template.icon}</div>
                    <div>{template.label}</div>
                  </div>
                ))}
              </div>
            </div>

            <div className="section">
              <div className="surveys-title">Ваши формы ({surveys.filter(s => !searchQuery || s.title.toLowerCase().includes(searchQuery.toLowerCase())).length})</div>
          {loading ? (
            <p style={{ color: "#6b7280", textAlign: "center", padding: "40px" }}>Загрузка...</p>
          ) : surveys.filter(s => !searchQuery || s.title.toLowerCase().includes(searchQuery.toLowerCase())).length === 0 ? (
            <div className="empty-state">
              <div className="empty-icon">📭</div>
              <p className="empty-text">{searchQuery ? "Формы не найдены" : "У вас еще нет форм"}</p>
              <p style={{ fontSize: "14px", color: "#9ca3af", marginBottom: "24px" }}>
                {searchQuery ? "Попробуйте другой запрос" : "Создайте первую форму или выберите шаблон"}
              </p>
              <button className="toolbar-btn" onClick={createNewForm}>
                ➕ Создать форму
              </button>
            </div>
          ) : (
            <div className="surveys-grid">
              {surveys.filter(s => !searchQuery || s.title.toLowerCase().includes(searchQuery.toLowerCase())).map(survey => (
                <div key={survey._id} className="survey-card">
                  <div className="survey-title">{survey.title}</div>
                  <div className="survey-meta">
                    {survey.questions?.length || 0} вопросов
                  </div>
                  <div className="survey-actions">
                    <button className="survey-action-btn" onClick={() => navigate(`/respond/${survey._id}`)}>
                      Ответить
                    </button>
                    <button className="survey-action-btn" onClick={() => navigate(`/editor/${survey._id}`)}>
                      Редактировать
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
        )}
      </div>
    </>
  );
}
